var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"스완…….","JPN":"スワン……","ENG":"Swan...","TWN":"史旺……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"스완 클레어, 맞지?","JPN":"スワン・クレアだよな？","ENG":"You're Swan Claire, correct?","TWN":"你是史旺·克萊爾，對吧？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"네 정체를 알고 있다.","JPN":"俺はお前の正体を知っている。","ENG":"I know who you are.","TWN":"我知道你的真實身份。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"죽고 싶지 않으면, 순순히 내 말을 따르도록.","JPN":"死にたくないなら、大人しく言うことを聞け。","ENG":"It's best for you to listen to my words if you want to live.","TWN":"如果不想死的話，就乖乖聽我的話。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"교활한 여배우라고 들었는데, 그래봤자 아직 여물지 못한 여자애로군.","JPN":"狡猾な女優だと聞いたが、所詮はまだ未熟な女の子だったか。","ENG":"I heard you were a cunning actress, but it turns out that you're just a little girl.","TWN":"聽說你是個狡猾的女演員，不過在我看來，你就是個不成熟的小女孩。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"넌 실수한 거다, 스완.","JPN":"残念だったな、スワン。","ENG":"You made a mistake, Swan.","TWN":"你犯了個大錯，史旺。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"세간에는 지금 심야의 살인마라는 녀석이 도시를 배회하며 먹잇감을 노린다고 하지.","JPN":"世間では今、深夜の殺人鬼とやらが獲物を探し徘徊していると噂になっているらしいが……","ENG":"The Midnight Killer is out loose in the city looking for prey.","TWN":"傳聞說現在有個午夜殺人魔在城市裡尋找獵物。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"그러니 이런 상황에서 시체 한 구쯤 더 생긴다고 달라질 건 아무것도 없어.","JPN":"こんな状況で死体がもう一体見つかったところで、何も変わりはしない。","ENG":"So another body on the streets doesn't change anything.","TWN":"在這種情況下，多一具屍體不會有什麼不同。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"다들 널 미치광이 살인마에게 살해당한 불쌍한 소녀라고 생각할 테니까.","JPN":"皆お前のことを殺人鬼に殺された哀れな少女だとしか思わないだろうから。","ENG":"Everyone will think that another poor girl fell victim to a crazy killer.","TWN":"大家都只會認為你是又一個被瘋子殺害的可憐少女。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"왜 아무 말이 없지? 겁이라도 먹었나?","JPN":"なんで黙り込んでいる？　怖気づいたか？","ENG":"Why aren't you saying anything? Cat got your tongue?","TWN":"怎麼一句話也不說？是害怕了嗎？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L18_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"자, 죽고 싶지 않으면, 바른대로 말해.","JPN":"さ、死にたくなければ素直に言え。","ENG":"Now, tell me the truth unless you want to die.","TWN":"好了，如果不想死的話，就老實說吧。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"<color=#ffd34c>사진</color>은 어디에 있나?","JPN":"<color=#ffd34c>写真</color>はどこにある？","ENG":"Where is the <color=#ffd34c>photo</color>?","TWN":"<color=#ffd34c>照片</color>在哪裡？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"죽고 싶지 않으면?","JPN":"死にたくなければ？","ENG":"Unless I want to die?","TWN":"不想死的話？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"글쎄요. 제가 죽으면 가장 곤란해질 사람은 제가 아니라 당신일 텐데요?","JPN":"さあ、私が死んで一番困るのはあなたのはずですが？","ENG":"Well. Wouldn't it be you who'll be in trouble if I die?","TWN":"未必，我要是死了，最麻煩的可不是我，而是你吧？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"뭐라고……?","JPN":"なんだと……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"아랫사람을 대하는 데 익숙한 듯, 딱딱하고 고압적인 말투…….","JPN":"目下の人間を扱うことに慣れているような、硬く高圧的な喋り方……","ENG":"That stiff and overbearing tone you use to order around your subordinates...","TWN":"習慣了對待下屬，生硬而高壓的語氣……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"꽤나 높은 직위를 가지셨던 것 같군요. 당신을 따르던 사람이 제법 많았을지도 모르죠.","JPN":"かなりお高い職位をお持ちになっていたようですね。大勢の人に仕えられていたかもしれません。","ENG":"Seems like you were in a fairly high position. I'm sure there used to be many under you.","TWN":"看來你曾經擁有相當高的職位，追隨你的人可能還不少呢。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 오른손을 미세하게 떨고 있어요. 아무래도 서부전선에서 신경을 다쳤겠죠.","JPN":"ですが、よく見ると右手が震えている。おそらく、西部戦線で神経をやられたのでしょう。","ENG":"But your right hand is trembling slightly. I assume you injured the nerves in your hand in the western front?","TWN":"但是你的右手在微微顫，應該是在西部前線受了傷，傷到神經了吧。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그렇게 손을 떨면 총을 잡을 수 없을 테니, 어쩔 수 없이 퇴역하셨겠고요.","JPN":"そんなに手が震えては銃を握ることも大変でしょう。やむを得ず退役したに違いありません。","ENG":"You can't possibly wield a gun when your hands are shaking like that. Which means you have been discharged.","TWN":"一個無法再握住槍，只能無奈退役的高階軍官……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"그, 그걸 어떻게……?","JPN":"な、なぜそれを……？","ENG":"H-how did you know that...?","TWN":"你，你怎麼會……？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"참으로 애석한 일이네요.","JPN":"まったく残念ですね。","ENG":"It truly is a pity.","TWN":"真是令人惋惜。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"나라를 위해 목숨을 바친 애국자가 퇴역 후, 높으신 분들 심부름꾼 노릇이나 하게 되다니.","JPN":"国のために命を捧げて戦ったのに、退役後はお偉いさんの使いっぱしりになり下がるなんて。","ENG":"A patriot risks his life for his country, then ends up as an errand boy for some high-ranking official.","TWN":"為國家獻出生命的愛國者退居幕後，竟然成為替高層跑腿的。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"저는 당신 <color=#ffd34c>의뢰인</color>에 대해 너무나 잘 알고 있답니다.","JPN":"私はあなたの<color=#ffd34c>依頼人</color>についてよく知っていますよ。","ENG":"I know your <color=#ffd34c>client</color> better than you think.","TWN":"我可是非常了解你的<color=#ffd34c>委託人</color>。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 그분께서 최대한 조용한 일 처리를 원하신다는 것 또한 말이죠.","JPN":"そしてその方が、なるべく静かにことを進めたいと望んでいらっしゃるということも。","ENG":"Also, he wants things to be done as quietly as possible.","TWN":"而且那位希望儘量低調行事。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"단도직입적으로 말씀드리죠.","JPN":"単刀直入に言いましょう。","ENG":"I will be honest with you.","TWN":"我就直接了當地說吧。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그분께서 원하는 사진은 지금 제 손에 없답니다.","JPN":"その方がお探しの写真は、今私の手元にはありません。","ENG":"I don't have the photo he demands with me right now.","TWN":"他想要的照片現在不在我手上。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 제 신변에 문제가 생길 경우, 자연스레 외부에 노출되도록 손을 써 두었죠.","JPN":"ですが、もし私の身に何かがあった場合、自然に外部へ晒されるように手を回しておいたのです。","ENG":"But I did take steps to make sure it would naturally get leaked if anything happened to me.","TWN":"但是如果我出了什麼事，我已經安排好了會讓它曝光。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"제가 죽으면, 조용한 일 처리를 바라는 그분께서 가장 원치 않는 상황이 벌어질 거예요.","JPN":"私が死ねば、依頼人にとって好ましくない状況になりますよ。","ENG":"If I die, the situation he wants to avoid will happen.","TWN":"如果我死了，最不想看到那種局面的就是他了吧？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그러니 오늘은 얌전히 돌아가셔서 그분께 전하도록 하세요.","JPN":"だから今日は大人しくお帰りになって、その方にお伝えください。","ENG":"So, I suggest you go back and tell him what I just told you.","TWN":"所以今天你還是乖乖回去，把話傳給他吧。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그렇게 스캔들이 두려우시다면, 배포를 좀 더 크게 가지시라고.","JPN":"スキャンダルがそんなに恐ろしいのなら、こそこそ裏から手を回すようなまねはおやめになったらと。","ENG":"That if he's that afraid of this scandal, he should be more generous.","TWN":"如果他真的那麼害怕醜聞，不妨把膽子放大一點。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"웃기지 마! 너 같은 여자애의 말을 어떻게 믿지!?","JPN":"ふざけるな！　何を根拠にお前の言葉を信用できる！？","ENG":"Don't make me laugh! Why should I trust the words of a little girl?!","TWN":"別逗了！我怎麼能相信你這種女人！"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"글쎄요. 제 말을 증명하는 건, 무척 간단한 일이랍니다.","JPN":"さあ？　私の言葉は簡単に証明できますよ。","ENG":"Well, proving that will be easy enough.","TWN":"這個嘛，證明的過程也非常簡單。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"절 죽이고, 제 집을 뒤져서 사진을 찾아보세요. 그럼 바로 알 수 있겠죠.","JPN":"私を殺して、私の自宅を漁って写真を探してみてください。そうすればわかるでしょう。","ENG":"Kill me now, then go rummage through my house for the photo. Then you'll know.","TWN":"殺了我，然後去我的家找找照片。你就會立刻明白了。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"물론, 무척 곤란해진 그분께서 당신에게 어떤 처분을 내릴지는 잘 모르겠지만.","JPN":"もちろん、困り果てたその方があなたにどういう処分を下すかまでは、わかりませんが。","ENG":"Of course, I'm not sure what kind of punishment will be dished out for what you've done.","TWN":"當然，我不太清楚他會如何處置你。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"거기 무슨 일이지?","JPN":"そこ、何をしている？","ENG":"What's going on over there?","TWN":"那裡發生什麼事了？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"왜 거리에서 언성을 높이고 있나?","JPN":"揉め事か？","ENG":"Who's yelling on the streets right now?","TWN":"為什麼在街上大喊大叫？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"……쳇.","JPN":"……ちっ。","ENG":"...Tch!","TWN":"……哼。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"이봐, 레이디가 곤란해하고 있지 않은가?","JPN":"おい、レディーが困っているではないか。","ENG":"Look here. Can't you see that a lady is in trouble?","TWN":"小姐，你是遇到麻煩了嗎？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"도, 도와주세요……!!","JPN":"た、助けてください……！！","ENG":"P-please, help me...!","TWN":"請，請幫幫我……！！"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"심야의 살인마예요……. 심야의 살인마가 절 죽이겠다고 했어요……!","JPN":"深夜の殺人鬼です……深夜の殺人鬼が、私を殺すと……！","ENG":"He's the Midnight Killer... He was about to kill me...!","TWN":"午夜殺人魔……午夜殺人魔要殺了我……！"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"심야의 살인마라고……?","JPN":"深夜の殺人鬼だと……？","ENG":"The Midnight Killer...?","TWN":"午夜殺人魔……？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"그, 그게 무슨……!?","JPN":"な、なんのつもりだ……！？","ENG":"W-what...?!","TWN":"什，什麼……？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"심야의 살인마라고? 또 살인마가 여기 나타났단 말이야?","JPN":"深夜の殺人鬼？　また殺人鬼が現れたの？","ENG":"The Midnight Killer? Another one has appeared here?","TWN":"午夜殺人魔？又有殺人魔出現在這裡了嗎？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"저쪽이다, 저쪽에서 목소리가 들렸어!","JPN":"あっちだ！　あっちから声が聞こえたぞ！","ENG":"Over there! I heard voices over there!","TWN":"在那邊，聲音是從那邊傳來的！"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"제길, 사람들이 몰려오는군.","JPN":"くそ、人が集まって来る。","ENG":"Dammit, people are coming.","TWN":"該死，人群湧過來了。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L24_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"이걸로 끝이라고 생각하지 마!","JPN":"これで終わると思うなよ！","ENG":"This isn't over!","TWN":"別以為這就完了！"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"잠깐, 거기 서……!!","JPN":"おい、待て……！！","ENG":"Hey! Stop right there...!","TWN":"等等，站住……！！"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"경관을 불렀어! 아직 멀리 가지 못했을 거야!","JPN":"警察を呼んだ！　まだ遠くには行ってないはずだ！","ENG":"I called the police! He couldn't have gone far!","TWN":"我去叫員警！他應該還沒跑遠！"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"망할 살인마 자식, 이젠 하다하다 여자아이까지 노릴 줄이야.","JPN":"殺人鬼のやつめ、女の子まで狙いやがるとは……","ENG":"That damned murderer. Now he's even going after little girls?","TWN":"該死的殺人狂，現在竟然連年輕女生都不放過。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"……정말 감사합니다.","JPN":"……本当に、ありがとうございます。","ENG":"...Thank you so much.","TWN":"……謝謝。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"신사분께서 구해주시지 않았다면, 저는 목숨을 잃었을지도 몰라요.","JPN":"あなたが助けてくださらなかったら、私は命を落としていたかもしれません。","ENG":"If you didn't come to my rescue, I would have lost my life.","TWN":"如果不是這位先生救了我，我可能已經喪命了。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"나야말로 자네를 구하게 되어서 영광이야.","JPN":"私こそ、君を助けることができて光栄だ。","ENG":"It's an honor to have saved you.","TWN":"這是我的榮幸。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"하마터면 런던에서 제일가는 유명 여배우를 잃을 뻔했으니까 말이지.","JPN":"危うくロンドンで一番の有名女優を失うところだったからな。","ENG":"For we almost lost London's most famous actress tonight.","TWN":"我們差一點就失去了倫敦最有名的女演員啊……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그러고 보니 당신은…….","JPN":"そういえばあなたは……","ENG":"Come to think of it, you...","TWN":"這麼說來你是……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"신사분께서는 혹시 제 공연을 보러 오신 적이 있지 않으신가요?","JPN":"私の公演を見に来たことがありますよね。","ENG":"Didn't you come to one of my performances?","TWN":"先生你是否曾來看過我的演出呢？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"후후…….","JPN":"ふふ……","ENG":"Haha...","TWN":"呵呵……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다네. 비록 멀리서 바라볼 뿐이지만 항상 응원하고 있어.","JPN":"そのとおりだ。ただ遠くから見守っているだけだが、いつも応援している。","ENG":"Although I saw from afar, I'll always be cheering for you.","TWN":"是的。雖然只能遠遠地看著，但我一直在為你加油。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"팬이니까 말이야, 자네의.","JPN":"ファンだからな、君の。","ENG":"I'm actually a fan of yours.","TWN":"史旺，我是你的粉絲。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 이렇게 멋진 신사분께서 응원해 주신다니 배우로서 영광이네요.","JPN":"ふふっ、こんなに素敵な紳士の方に応援していただけるなんて、俳優として身に余る光栄です。","ENG":"Haha, it's such an honor as an actress for such a gentleman to support me.","TWN":"哈哈，有這麼帥氣的紳士為我加油，身為演員真是榮幸。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L2_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"그나저나 객석에 있던 내 얼굴을 기억하는 건가?","JPN":"それにしても、君は客席にいた私の顔を覚えているのか？","ENG":"By the way, do you remember my face from the audience?","TWN":"難道說，你還記得那時候我的臉嗎？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L3_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"무대로부터 꽤 거리가 있었을 텐데?","JPN":"舞台からはかなり距離があったはずだが？","ENG":"It must've been quite far from the stage.","TWN":"那可是離舞台相當遠的地方啊？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"물론이에요. 저는 모든 팬분들을 기억하고 있답니다.","JPN":"もちろんです。私はファンの方全員のことを覚えています。","ENG":"Of course, I do. I remember all my fans' faces.","TWN":"當然了，我記得所有的粉絲。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그래요, 사흘 전 좌측 박스석이었죠? 그땐 어느 부인과 함께 계셨던 것 같은데…….","JPN":"そうですね……三日前、左側のボックス席でしたよね。あの時はご婦人とご一緒だったはず……","ENG":"Yes, you were sitting in the left box seat three days ago, right? I remember you were with another woman...","TWN":"嗯，是三天前，左側的包廂吧？那時好像和某位夫人一起……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 기혼자라기에 당신은…….","JPN":"ですがあなたは既婚者というには……","ENG":"But there's no ring on your...","TWN":"但是你沒戴著戒指，說明……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"앗, 죄송해요!","JPN":"あっ、ごめんなさい！","ENG":"Oh, my apologies!","TWN":"啊，我很抱歉！"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"사람을 관찰하는 게 버릇이라서요. 저도 모르게 신사분께 실례를 범하고 말았군요.","JPN":"人を観察するのが癖でして。つい失礼なことを言ってしまいましたね。","ENG":"I have a habit of observing others. Please excuse me for my rudeness.","TWN":"我有觀察別人的習慣，不知不覺中失禮了。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"괜찮아. 신경 쓸 것 없네.","JPN":"いいんだ。気にしなくていい。","ENG":"It's fine. No need to fret.","TWN":"沒關係，別在意。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 정말 대단한 기억력이로군.","JPN":"しかし、本当にすごい記憶力だ。","ENG":"Your memory is astounding by the way.","TWN":"不過你的記憶力真是驚人啊。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"한 번 읽은 대본과 노래를 외워버린다는 소문이 틀린 말이 아니었어.","JPN":"一度目を通した台本と歌はその場で覚えるという噂は本当だったのだな。","ENG":"They weren't lying when they said that you could memorize scripts and songs from reading them once.","TWN":"他們說你連讀過一次的劇本和歌曲都能記住，看來果然沒錯呢。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"과찬이세요. 그저 볼품없는 재주랍니다.","JPN":"大したことではありません。しがない特技です。","ENG":"It's too high of a praise. I just see it as a mediocre talent.","TWN":"你過獎了，這只是些微不足道的本事而已。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"볼품없다니? 무척이나 훌륭한 재능일세.","JPN":"しがない？　いいや、それは立派な才能だ。","ENG":"Mediocre? I think it's a wonderful talent to have.","TWN":"微不足道？這可是非常出色的才能啊。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"내가 오랫동안 찾고 있었던 부류의 재능이지.","JPN":"私が長い間探し続けていた類の才能だよ。","ENG":"It's something that I've been searching years for.","TWN":"也是我一直在尋找的那種才能。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"……네? 그게 무슨?","JPN":"……え？　それはどういう……？","ENG":"...Excuse me? I don’t understand...","TWN":"……嗯？什麼意思？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"아무래도 소란이 가라앉은 모양이군.","JPN":"どうやら騒ぎは一段落したようだな。","ENG":"It seems that the commotion has died down.","TWN":"看來騷動已經平息了。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"가지. 런던의 심야는 위험해. 자네만 원한다면 자택까지 에스코트해주겠네.","JPN":"行こう。深夜のロンドンは危険だ。君さえよければ、自宅までエスコートしよう。","ENG":"Let's go. Late nights in London are dangerous. If you want, I'll escort you to your home.","TWN":"走吧。倫敦的深夜很危險，如果願意的話，請讓我護送你回家。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"아니요, 괜찮답니다. 신사분께 더는 누를 끼칠 수는 없으니까요.","JPN":"いいえ、大丈夫です。あなたにこれ以上ご迷惑をおかけするわけにはいきません。","ENG":"No, I'll be all right. I don't wish to bother you any further.","TWN":"不，謝謝了。我不能再給你添麻煩了，先生。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 보기 좋게 차여버렸군.","JPN":"ふふ、体よく断わられてしまったか。","ENG":"Haha, serves me right to get rejected.","TWN":"哈哈，被漂亮地拒絕了。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"역시 유명 여배우의 마음을 얻는 건 쉽지 않은 모양이야.","JPN":"やはり有名女優の心を手に入れるのは、そう簡単にはいかないな。","ENG":"It's not easy winning the heart of a famous actress, I suppose.","TWN":"果然，想要贏得著名女演員的心並不容易啊。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그렇지 않아요. 저는 항상 무대에서 기다리고 있답니다.","JPN":"そんなことはありません。私はいつも舞台で待っていますよ。","ENG":"That's not true. I'm always waiting on the stage.","TWN":"不是這樣的，我可是一直在舞台上等著你呢。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그러니까 신사분께서 원하신다면 언제든 볼 수 있어요.","JPN":"あなたが望むなら、いつだって舞台でお会いできます。","ENG":"So you can see me whenever you want.","TWN":"所以，如果你願意的話，隨時都可以見面。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"그래. 그렇게 생각하는 것도 나쁘진 않겠어.","JPN":"そうか。そう考えるのも悪くはないね。","ENG":"Very well. That's a positive way of thinking.","TWN":"是啊，這樣想也不錯。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"그럼, 자네와의 다음 만남을 손꼽아 기다리도록 하지.","JPN":"では、また君に出会える日を心待ちにするとしよう。","ENG":"Then, I'll look forward to the day we meet again.","TWN":"那麼，我會期待與你的下次見面。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"좋은 밤 보내길, 스완 클레어.","JPN":"おやすみ。スワン・クレア。","ENG":"Goodnight, Swan Claire.","TWN":"晚安，史旺·克萊爾。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"subtitle","speaker":null,"text":{"KOREA":"일주일 뒤.","JPN":"一週間後","ENG":"A week later.","TWN":"一周後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 9월 18일 런던, 로열 오페라 하우스","JPN":"1888年9月18日　ロンドン、ロイヤルオペラハウス","ENG":"September 18, 1888, London. Royal Opera House","TWN":"1888年9月18日 倫敦，皇家歌劇院"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"고생 많았어, 스완! 오늘도 전부 매진이었다고!","JPN":"お疲れ様、スワン！　今日もチケットは完売だったよ！","ENG":"Great work out here, Swan! We sold out tonight again!","TWN":"辛苦了，史旺！今天的票也全部賣完了！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"이대로만 가면 연말에는 해외 순회공연도 꿈이 아니겠는데?","JPN":"この調子だと、年末は海外巡回公演も夢じゃないね！","ENG":"At this rate, we might even be doing an overseas tour at the end of the year!","TWN":"照這樣下去，年底的海外巡演也不是夢了吧？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"어라? 왜 그래? 안색이 창백한데? 어디 아파?","JPN":"あれ、どうしたの？　顔色が悪いよ。どこか具合でも悪い？","ENG":"Huh? What's wrong? You don't look so good. Are you feeling sick?","TWN":"欸？怎麼了？臉色這麼蒼白？是哪裡不舒服嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"메리, 미안하지만 지금 몇 시야?","JPN":"ごめん、メリー。今何時？","ENG":"Mary, I'm sorry, but what time is it?","TWN":"瑪麗，不好意思，現在幾點了？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"몇 시냐고?","JPN":"え、今？","ENG":"What time is it?","TWN":"你問現在幾點？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"으음, 방금 게 마지막 무대였으니까 저녁 8시쯤 됐겠지. 밖에서 시계탑이라도 보고 올까?","JPN":"うーん、さっきのが今日の最終公演だったから夜の8時ぐらいよ。外の時計塔を確かめればはっきりするけど……","ENG":"Um, this was the last performance of the day, so it should be around 8 o'clock. Should I go check the clock tower?","TWN":"嗯……剛才是最後一場演出，現在應該是晚上8點左右，要不要出去看看鐘樓？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"뭔가 이상해.","JPN":"何か変だわ。","ENG":"Something's wrong.","TWN":"感覺有些不太對勁。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"벌써 우정국이 문 닫을 시간인데. 아직도 도착하지 않았잖아.","JPN":"もう郵便の配達は終わっている時間なのに、まだ届いていないの。","ENG":"The post office should be closed by now, but it hasn't arrived yet.","TWN":"郵局已經關門了，為什麼還沒到呢……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"도착하지 않았다니? 뭐가?","JPN":"届いてない？　何が？","ENG":"What hasn't arrived?","TWN":"沒到？什麼沒到？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"왕실 우표가 붙은 <color=#ffd34c>팬레터</color> 말이야.","JPN":"王室の切手が貼られた<color=#ffd34c>ファンレター</color>よ。","ENG":"The <color=#ffd34c>fan letter</color> with the royal stamp.","TWN":"那封貼有王室郵票的<color=#ffd34c>粉絲信</color>啊。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"늦어도 항상 마지막 공연이 끝날 때쯤에는 도착했잖아.","JPN":"どんなに遅くても、いつも最終公演が終わるころには届いていたのに。","ENG":"It always arrived around the time our last performance of the day ended.","TWN":"即使會遲些，也總會在最後一場演出結束時到的。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"팬레터……?","JPN":"ファンレター……？","ENG":"Fan letter...?","TWN":"粉絲信……？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"아아, 그 기분 나쁜 편지를 말하는 거야? 그게 왜?","JPN":"ああ、あの気持ち悪い手紙のことね。それがどうしたの？","ENG":"Oh! You mean that creepy one? What about it?","TWN":"啊啊，你是說那封令人不舒服的信嗎？怎麼了？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"왜냐니?","JPN":"どうしたのって？","ENG":"What about it?","TWN":"怎麼了？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"왕실 우표는 왕실에서 우편 서비스의 신뢰를 보증한다는 뜻이야.","JPN":"王室の切手は、王室が郵便サービスを保証するという意味よ。","ENG":"The royal stamp means that the royal family guarantees the credibility of the postal service.","TWN":"皇家郵票代表皇家對郵政服務信譽的保證。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"정해진 시간에, 안전하게, 수신인에게 직접 전달되야 해. 그래서 우표 값이 비싼 거라고.","JPN":"決まった時間に、安全に、受取人に直接届かなければならない。だから高価なの。","ENG":"It must be delivered safely to the recipient on time. That's why it's so expensive.","TWN":"必須在規定的時間內，安全地、直接地交到收件人手中。所以郵票才會這麼貴。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"누군가 집배 과정에서 일부러 누락시키지 않는 한, 이런 일이 발생할 리 없어.","JPN":"誰かが集配の過程でわざと隠したりでもしない限り、こんなことはありえない。","ENG":"Unless someone intentionally omits it during the delivery process, there's no way something like this should happen.","TWN":"除非有人在投遞過程中故意漏掉，否則這種事情不可能發生。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"발생할 리가 없는데……. 어째서……?","JPN":"ありえないはず……なのにどうして……？","ENG":"It shouldn't happen, but... why...?","TWN":"不可能發生的……為什麼……？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"어어, 그게 내 말뜻은…….","JPN":"ええと、だからその……","ENG":"Um, so what I'm trying to say is...","TWN":"呃呃，我的意思是……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"네가 왜 그런 수상한 편지를 기다리냐는 뜻이었는데…….","JPN":"あなたがその怪しい手紙を待つ理由が、よくわからないんだけど……","ENG":"Why are you waiting for that suspicious letter to arrive...?","TWN":"為什麼你要等那種可疑的信件……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"……다행이다. 편지가 도착했나 봐.","JPN":"……よかった。手紙が届いたみたい。","ENG":"...Phew. I think it's here.","TWN":"……太好了，信好像到了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"역시 괜한 걱정이었던 모양이야.","JPN":"やっぱり杞憂だったようね。","ENG":"Guess I got worried over nothing.","TWN":"果然擔心是多餘的。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"네, 들어오세요!","JPN":"はい、どうぞお入りください。","ENG":"Yes, come in!","TWN":"請進！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"……후후.","JPN":"……ふふ。","ENG":"...Haha.","TWN":"……呵呵。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"이렇게 또 금방 보게 되는 군, 스완 클레어.","JPN":"意外とすぐに再会できたな、スワン・クレア。","ENG":"We meet again so soon, Swan Claire.","TWN":"這麼快又見面了，史旺·克萊爾。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"당신은 그때 그……?","JPN":"あなたは、あの時の……？","ENG":"You're that gentleman from...","TWN":"你是那時候的……？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"어라? 누구야, 이 잘생긴 신사분은? 아는 분이셔?","JPN":"あら？　誰なの、この素敵な紳士さんは。知り合い？","ENG":"Huh? Who's this handsome gentleman? Someone you know?","TWN":"呃……這位帥氣的紳士是誰啊？你們認識嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"적잖게 놀란 표정인데.","JPN":"ずいぶん驚いたようだな。","ENG":"You seem startled.","TWN":"你看起來相當驚訝。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"오늘 공연도 무척이나 훌륭했다네.","JPN":"今日の公演もとても素晴らしかったよ。","ENG":"Tonight's performance was excellent.","TWN":"今天的演出也非常精彩，克萊爾小姐。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"무슨 일이죠?","JPN":"何のご用ですか？","ENG":"What brings you here?","TWN":"什麼事？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"당신이 어째서 여기에?","JPN":"あなたがなぜここに？","ENG":"What are you doing here?","TWN":"你為什麼在這裡？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"하하, 다른 게 아니라, 자네에게 줄 선물을 준비했거든.","JPN":"はは、大したことではない。君にちょっとしたプレゼントを用意したんだよ。","ENG":"Haha. Nothing much, but I prepared a present for you.","TWN":"哈哈，不為別的，作為你的粉絲……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"자네의 팬으로서 말이야.","JPN":"君のファンとしてね。","ENG":"As a fan, of course.","TWN":"我準備了一份禮物要送給你。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"무슨 말씀인지 잘 모르겠네요.","JPN":"どういう意味なのか、よく理解できません。","ENG":"I'm not sure if I understand.","TWN":"我不太明白你在說什麼。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"신사께서 호의를 베푸시는 건 감사하지만, 여긴 제 개인 대기실이랍니다.","JPN":"ご厚意はありがたいのですが、ここは私のプライベートな控え室です。","ENG":"I appreciate your kindness, but this is my personal waiting room.","TWN":"感謝這位先生的好意，但這裡是我的私人休息室。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그러니 마음만 받도록 하죠. 이만 돌아가 주세요.","JPN":"お気持ちだけ受け取っておきます。もうお引き取りください。","ENG":"Although I'm grateful, I'll have to decline. Please go back.","TWN":"你的心意我領了，請回吧。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"그래? 이거 아쉽게 됐어.","JPN":"そうか。それは残念だな。","ENG":"Is that so? What a shame.","TWN":"這樣啊？真是可惜。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"그럼 이 <color=#ffd34c>편지</color>는 끝내 주인에게 전달되지 못하겠군.","JPN":"では、この<color=#ffd34c>手紙</color>は永遠に届けられないということだ。","ENG":"I won't be able to deliver this <color=#ffd34c>letter</color> to its owner.","TWN":"那這封<color=#ffd34c>信</color>就永遠無法送到主人手中了。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"저건? 왕실 우표가 붙어있는……?","JPN":"あれは、王室の切手が貼られてる……？","ENG":"That's...! A royal stamp...?","TWN":"那是？貼有皇家郵票的……？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"펜레터……!","JPN":"ファンレター……！","ENG":"It's that fan letter...!","TWN":"粉絲信……！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그걸 어째서 당신이……!?","JPN":"どうしてあなたがそれを……！？","ENG":"How do you have it...?!","TWN":"為什麼會在你手上……！？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 그러니까 몇 번이나 말하지 않았나?","JPN":"ふふ、だから言ったじゃないか。","ENG":"Haha, didn't I say many times before?","TWN":"呵呵，我不是說了很多遍了嗎？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"자네의 팬이라고.","JPN":"私は君のファンなんだってね。","ENG":"I'm your fan.","TWN":"我是你的粉絲。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};